<template>
  <div class="homepage">
    <div class="home_img">
      <el-image :src=home fit="fill"></el-image>
    </div>
  <el-container>
    <el-aside width="70%">
      <div class="module_1_text">
            {{module_1_text}}
      </div>
    </el-aside>
    <el-main class="module1_image">
        <el-image :src=module1 fit="fill"></el-image>
    </el-main>
  </el-container>
  <el-container>
    <mavon-editor v-model="module2_markdown" :toolbars="toolbars" @change="handleChange" />
    <el-aside width="70%" v-html="renderedHtml2" class="markdown-preview">
    </el-aside>
  </el-container>
  <el-container>
    <mavon-editor v-model="module3_markdown" :toolbars="toolbars" @change="handleChange" />
    <el-aside width="70%" v-html="renderedHtml3" class="markdown-preview">
    </el-aside>
  </el-container>
  <el-container>
    <el-aside width="100%" class="timeline" >
      <vue-horizon-timeline :items="events" timeline-background=white timeline-padding="10px" class="timeline" />
    </el-aside>
  </el-container>
  </div>
</template>

<script>
import MarkdownIt from 'markdown-it'
import MavonEditor from 'mavon-editor'
import VueHorizonTimeline from 'vue-horizontal-timeline'
import home from '@/assets/home.png'
import module1 from '@/assets/home_module1.png'
export default {
  name: 'HomePage',
  components: {
    MavonEditor,
    VueHorizonTimeline
  },
  data () {
    return {
      home: home,
      module1: module1,
      nav_list: [
        {text: '首页', path: '/'},
        {text: '平台介绍', path: '/demo'},
        {text: '数据集和开源代码', path: '/dataset'},
        {text: '研究课题和论文清单', path: '/paper'},
        {text: '新闻', path: '/news'},
        {text: '活动', path: '/activity'},
        {text: '团队', path: '/group'},
        {text: '合作单位', path: '/coauthor'}],
      module_1_text: `With the integration of large language models (LLMs),
        embodied agents havestrong capabilities to execute complicated instructions in natural language, paving
        a way for the potential deployment of embodied robots. However, a foreseeable
        issue is that those embodied agents can also flawlessly execute some hazardous
        tasks, potentially causing damages in real world. To study this issue, we present
        SafeAgentBench—a new benchmark for safety-aware task planning of embodied
        LLMagents. SafeAgentBench includes: (1) a new dataset with 750 tasks, covering
        10 potential hazards and 3 task types; (2) SafeAgentEnv, a universal embodied
        environment with a low-level controller, supporting multi-agent execution with
        17 high-level actions for 8 state-of-the-art baselines; and (3) reliable evaluation
        methods from both execution and semantic perspectives. Experimental results
        show that the best-performing baseline gets 69% success rate for safe tasks, but
        only 5% rejection rate for hazardous tasks, indicating significant safety risks.`,
      module2_markdown: '# News \n - 论文中了\n - 我们投出了第一篇论文\n - 我们搭建了field trail！\n',
      module3_markdown: '# 研究方向和研究脉络\n - LLM-powered agent for Network automation\n 简要概括\n - Digital twins for optical networks\n 简要概括',
      toolbars: {
        bold: true, // 加粗按钮
        italic: true, // 斜体按钮
        header: true // 标题按钮
        // 可以根据需要添加更多工具按钮，参考文档：https://github.com/hinesboy/mavonEditor
      },
      events: [
        {
          time: '2023-09',
          title: '2023-09',
          content: 'Lab testbed'
        },
        {
          time: '2024-06',
          title: '2024-06',
          content: 'Field trial testbed in China'
        },
        {
          time: '2024-09',
          title: '2024-09',
          content: 'First LLM-enhanced agent for lifecycle management'
        },
        {
          time: '2024-10',
          title: '2024-09',
          content: 'First LLM-enhanced agent for lifecycle management'
        },
        {
          time: '2024-11',
          title: '2024-09',
          content: 'First LLM-enhanced agent for lifecycle management'
        }
      ]
    }
  },
  created () {
    console.log('HomePage一创建')
  },
  computed: {
    renderedHtml2 () {
      const md = new MarkdownIt()
      return md.render(this.module2_markdown)
    },
    renderedHtml3 () {
      const md = new MarkdownIt()
      return md.render(this.module3_markdown)
    }
  },
  methods: {
    handleChange (value, render) {
      console.log('Markdown 内容发生改变:', value)
      console.log('渲染后的 HTML:', render)
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
.home_img{
  margin: 2em 0 0 0;
}
.module_1_text{
  text-align:left
}
.module1_image:hover{
  transform: scale(1.05);
}

.markdown-preview {
  text-align: left !important;
}
  .el-aside {
    color: #333;
    text-align: center;
    padding: 2em 0 1em 10em;
    line-height: 1.8;
    font-size: 18px;
    font-family: "微软雅黑"
  }
  .el-main {
    color: #333;
    text-align: left;
    width:100%;
  }
  .timeline{
    padding: 0;
  }
</style>



