<template>
  <div class="navi_bar">
      <el-menu
    class="el-menu-demo"
    mode="horizontal"
    background-color="#545c64"
    text-color="#fff"
    active-text-color="#ffd04b"
    router=router>
    <el-menu-item
        v-for="(item, index) in nav_list" :key="index" :index="item.path" class="item" >
        {{ item.text }}
      </el-menu-item>
</el-menu>
  </div>
</template>

<script>
export default {
  name: 'NavBar',
  data () {
    return {
      menuProps: {
        router: true
      },
      nav_list: [
        {text: '首页', path: '/'},
        {text: '平台介绍', path: '/demo'},
        // {text: '数据集和开源代码', path: '/dataset'},
        {text: '研究课题和论文清单', path: '/paper'},
        {text: '新闻', path: '/news'},
        // {text: '活动', path: '/activity'},
        {text: '团队', path: '/group'}
        // {text: '合作单位', path: '/coauthor'}
      ]
    }
  }
}
</script>

<!-- Add "scoped" attribute to limit CSS to this component only -->
<style scoped>
.item{
  width:20%;
  font-size: 20px;
}
</style>



